import type * as DMMF from '@prisma/dmmf'

import { scalarToTs } from './scalar-type-map'

/**
 * Returns the TypeScript base type for a DMMF field, or `null` if the field
 * should be excluded from generated output (relations, unsupported kinds).
 */
function fieldTsType(field: DMMF.Field): string | null {
  if (field.kind === 'scalar') {
    return scalarToTs(field.type)
  }
  if (field.kind === 'enum') {
    return field.type
  }
  // Skip relation ('object') and unsupported fields.
  return null
}

/** Returns true if the field is auto-managed by the database and must be excluded from write inputs. */
function isAutoManaged(field: DMMF.Field): boolean {
  return (field.isId && field.hasDefaultValue) || field.isUpdatedAt === true || field.isGenerated === true
}

function toKebabCase(s: string): string {
  return s.replace(/([a-z])([A-Z])/g, '$1-$2').toLowerCase()
}

/**
 * Generates TypeScript interface declarations and a per-model client factory
 * function for a single Prisma model.
 *
 * The emitted factory function references `RestApiClientConfig` and
 * `httpRequest`, which are produced by {@link generateHttpHelpers}.
 */
export function generateModelCode(model: DMMF.Model): string {
  const n = model.name
  const includedFields = model.fields.filter((f) => fieldTsType(f) !== null)
  const lines: string[] = []

  // Model interface — reflects the full shape returned by the server
  lines.push(`export interface ${n} {`)
  for (const f of includedFields) {
    const t = fieldTsType(f)!
    const tsType = f.isList ? `${t}[]` : t
    const nullable = !f.isRequired && !f.isList ? ' | null' : ''
    lines.push(`  ${f.name}: ${tsType}${nullable}`)
  }
  lines.push(`}`, '')

  // CreateInput — omit auto-managed fields; nullable / defaulted fields are optional
  const createFields = includedFields.filter((f) => !isAutoManaged(f))
  lines.push(`export interface ${n}CreateInput {`)
  for (const f of createFields) {
    const t = fieldTsType(f)!
    const tsType = f.isList ? `${t}[]` : t
    const nullable = !f.isRequired && !f.isList ? ' | null' : ''
    const opt = !f.isRequired || f.hasDefaultValue ? '?' : ''
    lines.push(`  ${f.name}${opt}: ${tsType}${nullable}`)
  }
  lines.push(`}`, '')

  // UpdateInput — omit id and auto-managed fields; all remaining fields are optional
  const updateFields = includedFields.filter((f) => !f.isId && !isAutoManaged(f))
  lines.push(`export interface ${n}UpdateInput {`)
  for (const f of updateFields) {
    const t = fieldTsType(f)!
    const tsType = f.isList ? `${t}[]` : t
    const nullable = !f.isRequired && !f.isList ? ' | null' : ''
    lines.push(`  ${f.name}?: ${tsType}${nullable}`)
  }
  lines.push(`}`, '')

  // WhereInput — all scalar/enum fields as optional equality filters
  lines.push(`export interface ${n}WhereInput {`)
  for (const f of includedFields) {
    const t = fieldTsType(f)!
    const tsType = f.isList ? `${t}[]` : t
    lines.push(`  ${f.name}?: ${tsType}`)
  }
  lines.push(`}`, '')

  // WhereUniqueInput — only @id and @unique fields
  const uniqueFields = includedFields.filter((f) => f.isId || f.isUnique)
  lines.push(`export interface ${n}WhereUniqueInput {`)
  for (const f of uniqueFields) {
    const t = fieldTsType(f)!
    const tsType = f.isList ? `${t}[]` : t
    lines.push(`  ${f.name}?: ${tsType}`)
  }
  lines.push(`}`, '')

  // Per-model client interface
  lines.push(`export interface ${n}Client {`)
  lines.push(`  findMany(where?: ${n}WhereInput): Promise<${n}[]>`)
  lines.push(`  findUnique(where: ${n}WhereUniqueInput): Promise<${n} | null>`)
  lines.push(`  create(data: ${n}CreateInput): Promise<${n}>`)
  lines.push(`  update(where: ${n}WhereUniqueInput, data: ${n}UpdateInput): Promise<${n}>`)
  lines.push(`  delete(where: ${n}WhereUniqueInput): Promise<${n}>`)
  lines.push(`}`, '')

  // Per-model client factory (references httpRequest defined in the HTTP helpers section)
  const urlPath = toKebabCase(n)
  lines.push(`function create${n}Client(config: RestApiClientConfig): ${n}Client {`)
  lines.push(`  const base = '/${urlPath}'`)
  lines.push(`  return {`)
  lines.push(`    findMany: (where?) => httpRequest<${n}[]>(config, 'GET', base, undefined, where),`)
  lines.push(`    findUnique: (where) => httpRequest<${n} | null>(config, 'GET', \`\${base}/unique\`, undefined, where),`)
  lines.push(`    create: (data) => httpRequest<${n}>(config, 'POST', base, data),`)
  lines.push(`    update: (where, data) => httpRequest<${n}>(config, 'PATCH', \`\${base}/update\`, { where, data }),`)
  lines.push(`    delete: (where) => httpRequest<${n}>(config, 'DELETE', base, undefined, where),`)
  lines.push(`  }`)
  lines.push(`}`)

  return lines.join('\n')
}

