import fs from 'node:fs/promises'
import path from 'node:path'

import type * as DMMF from '@prisma/dmmf'

import { generateModelCode } from './model-codegen'

export interface GenerateRestClientOptions {
  dmmf: DMMF.Document
  outputDir: string
}

const FILE_HEADER = `\
// =============================================================================
// Generated by @prisma/client-generator-rest — do not edit manually.
// =============================================================================
`

/**
 * Emits the shared HTTP infrastructure types and the internal `httpRequest`
 * helper that all generated model clients rely on.
 *
 * The function is intentionally not exported from the generated file so that
 * consumers interact only through the typed model clients.
 */
const HTTP_HELPERS = `\
export interface RestApiClientConfig {
  /** Base URL of the REST API server, e.g. \`"https://api.example.com"\`. */
  baseUrl: string
  /** Optional HTTP headers sent with every request (e.g. for authentication). */
  headers?: Record<string, string>
}

async function httpRequest<T>(
  config: RestApiClientConfig,
  method: string,
  urlPath: string,
  body?: unknown,
  params?: object,
): Promise<T> {
  const url = new URL(\`\${config.baseUrl}\${urlPath}\`)
  if (params) {
    for (const [key, value] of Object.entries(params)) {
      if (value !== undefined && value !== null) {
        url.searchParams.set(key, String(value))
      }
    }
  }
  const response = await fetch(url.toString(), {
    method,
    headers: {
      'Content-Type': 'application/json',
      ...config.headers,
    },
    body: body !== undefined ? JSON.stringify(body) : undefined,
  })
  if (!response.ok) {
    const text = await response.text()
    throw new Error(\`HTTP \${response.status} \${response.statusText}: \${text}\`)
  }
  return response.json() as Promise<T>
}
`

function generateEnums(enums: DMMF.Datamodel['enums']): string {
  if (enums.length === 0) return ''
  return enums
    .map((e) => {
      const entries = e.values.map((v) => `  ${v.name}: '${v.name}',`).join('\n')
      return [
        `export const ${e.name} = {`,
        entries,
        `} as const`,
        `export type ${e.name} = (typeof ${e.name})[keyof typeof ${e.name}]`,
      ].join('\n')
    })
    .join('\n\n')
}

function toCamelCase(s: string): string {
  return s.charAt(0).toLowerCase() + s.slice(1)
}

function generateMainClient(models: DMMF.Datamodel['models']): string {
  const lines: string[] = []

  lines.push(`/** Top-level REST API client with a typed sub-client for each Prisma model. */`)
  lines.push(`export interface PrismaRestApiClient {`)
  for (const m of models) {
    lines.push(`  ${toCamelCase(m.name)}: ${m.name}Client`)
  }
  lines.push(`}`, '')

  lines.push(`/**`)
  lines.push(` * Creates a fully-typed REST API client for all Prisma models.`)
  lines.push(` *`)
  lines.push(` * @example`)
  lines.push(` * \`\`\`ts`)
  lines.push(` * const client = createPrismaRestApiClient({ baseUrl: 'https://api.example.com' })`)
  lines.push(` * const users = await client.user.findMany()`)
  lines.push(` * const post  = await client.post.create({ data: { title: 'Hello' } })`)
  lines.push(` * \`\`\``)
  lines.push(` */`)
  lines.push(`export function createPrismaRestApiClient(config: RestApiClientConfig): PrismaRestApiClient {`)
  lines.push(`  return {`)
  for (const m of models) {
    lines.push(`    ${toCamelCase(m.name)}: create${m.name}Client(config),`)
  }
  lines.push(`  }`)
  lines.push(`}`)

  return lines.join('\n')
}

/**
 * Generates a typed REST API client from the provided DMMF and writes a
 * single `index.ts` file into `outputDir`.
 */
export async function generateRestClient({ dmmf, outputDir }: GenerateRestClientOptions): Promise<void> {
  const { models, enums } = dmmf.datamodel

  const sections: string[] = [FILE_HEADER, HTTP_HELPERS]

  const enumSection = generateEnums(enums)
  if (enumSection) {
    sections.push(enumSection)
  }

  for (const model of models) {
    sections.push(generateModelCode(model))
  }

  sections.push(generateMainClient(models))

  await fs.mkdir(outputDir, { recursive: true })
  await fs.writeFile(path.join(outputDir, 'index.ts'), sections.join('\n'), 'utf-8')
}

