import os from 'node:os'
import path from 'node:path'

import { afterEach, beforeEach, describe, expect, it } from 'vitest'

import { generateRestClient } from '../generate-rest-client'
import { scalarToTs } from '../scalar-type-map'

// ---------------------------------------------------------------------------
// Helpers
// ---------------------------------------------------------------------------

/** Minimal DMMF document factory for use in tests. */
function makeDmmf(
  models: {
    name: string
    fields: {
      name: string
      kind?: 'scalar' | 'object' | 'enum' | 'unsupported'
      type: string
      isRequired?: boolean
      isList?: boolean
      isId?: boolean
      isUnique?: boolean
      isReadOnly?: boolean
      hasDefaultValue?: boolean
      isUpdatedAt?: boolean
      isGenerated?: boolean
    }[]
  }[],
  enums: { name: string; values: { name: string; dbName: string | null }[] }[] = [],
) {
  return {
    datamodel: {
      models: models.map((m) => ({
        name: m.name,
        dbName: null,
        schema: null,
        fields: m.fields.map((f) => ({
          kind: f.kind ?? 'scalar',
          name: f.name,
          type: f.type,
          isRequired: f.isRequired ?? true,
          isList: f.isList ?? false,
          isId: f.isId ?? false,
          isUnique: f.isUnique ?? false,
          isReadOnly: f.isReadOnly ?? false,
          hasDefaultValue: f.hasDefaultValue ?? false,
          isUpdatedAt: f.isUpdatedAt,
          isGenerated: f.isGenerated,
        })),
        uniqueFields: [],
        uniqueIndexes: [],
        primaryKey: null,
      })),
      enums,
      types: [],
      indexes: [],
    },
    schema: {
      inputObjectTypes: {},
      outputObjectTypes: { model: [], prisma: [] },
      enumTypes: { prisma: [] },
      fieldRefTypes: {},
    },
    mappings: { modelOperations: [], otherOperations: { read: [], write: [] } },
  } as any // cast so tests don't need to satisfy the full ReadonlyDeep shape
}

// ---------------------------------------------------------------------------
// scalarToTs
// ---------------------------------------------------------------------------

describe('scalarToTs', () => {
  it.each([
    ['String', 'string'],
    ['Int', 'number'],
    ['Float', 'number'],
    ['Decimal', 'number'],
    ['Boolean', 'boolean'],
    ['DateTime', 'Date'],
    ['Json', 'unknown'],
    ['Bytes', 'Uint8Array'],
    ['BigInt', 'bigint'],
  ])('maps %s → %s', (prismaType, expected) => {
    expect(scalarToTs(prismaType)).toBe(expected)
  })

  it('falls back to unknown for unrecognized types', () => {
    expect(scalarToTs('SomeCustomType')).toBe('unknown')
  })
})

// ---------------------------------------------------------------------------
// generateRestClient
// ---------------------------------------------------------------------------

describe('generateRestClient', () => {
  let tmpDir: string

  beforeEach(async () => {
    tmpDir = await fs.mkdtemp(path.join(os.tmpdir(), 'prisma-rest-gen-'))
  })

  afterEach(async () => {
    await fs.rm(tmpDir, { recursive: true, force: true })
  })

  async function generate(dmmf: any): Promise<string> {
    await generateRestClient({ dmmf, outputDir: tmpDir })
    return fs.readFile(path.join(tmpDir, 'index.ts'), 'utf-8')
  }

  it('creates the output directory and index.ts', async () => {
    const nested = path.join(tmpDir, 'deep', 'dir')
    await generateRestClient({ dmmf: makeDmmf([]), outputDir: nested })
    const stat = await fs.stat(path.join(nested, 'index.ts'))
    expect(stat.isFile()).toBe(true)
  })

  it('includes the generated-file header', async () => {
    const output = await generate(makeDmmf([]))
    expect(output).toContain('@prisma/client-generator-rest')
    expect(output).toContain('do not edit manually')
  })

  it('emits RestApiClientConfig and httpRequest helpers', async () => {
    const output = await generate(makeDmmf([]))
    expect(output).toContain('export interface RestApiClientConfig')
    expect(output).toContain('baseUrl: string')
    expect(output).toContain('async function httpRequest<T>')
  })

  describe('model interfaces', () => {
    const dmmf = makeDmmf([
      {
        name: 'User',
        fields: [
          { name: 'id', type: 'Int', isId: true, hasDefaultValue: true },
          { name: 'email', type: 'String', isUnique: true },
          { name: 'name', type: 'String', isRequired: false },
          { name: 'score', type: 'Float' },
          { name: 'active', type: 'Boolean' },
          { name: 'createdAt', type: 'DateTime', hasDefaultValue: true },
          // relation field — should be excluded
          { name: 'posts', kind: 'object' as const, type: 'Post', isRequired: false },
          // updatedAt — should be excluded from write inputs
          { name: 'updatedAt', type: 'DateTime', isUpdatedAt: true, hasDefaultValue: true },
        ],
      },
    ])

    it('generates the model interface', async () => {
      const output = await generate(dmmf)
      expect(output).toContain('export interface User {')
      expect(output).toContain('id: number')
      expect(output).toContain('email: string')
      expect(output).toContain('name: string | null')
      expect(output).toContain('score: number')
      expect(output).toContain('active: boolean')
      // relation field must not appear
      expect(output).not.toContain('posts:')
    })

    it('generates CreateInput without auto-managed fields', async () => {
      const output = await generate(dmmf)
      expect(output).toContain('export interface UserCreateInput {')
      // id has default — must be absent from CreateInput
      expect(output).not.toMatch(/UserCreateInput \{[^}]*\bid:/)
      // updatedAt is auto-managed — must be absent
      expect(output).not.toMatch(/UserCreateInput \{[^}]*\bupdatedAt:/)
      // required field without default is mandatory
      expect(output).toMatch(/UserCreateInput \{[^}]*email: string/)
      // nullable field is optional
      expect(output).toMatch(/UserCreateInput \{[^}]*name\?: string \| null/)
      // field with default is optional
      expect(output).toMatch(/UserCreateInput \{[^}]*createdAt\?: Date/)
    })

    it('generates UpdateInput without id and auto-managed fields', async () => {
      const output = await generate(dmmf)
      expect(output).toContain('export interface UserUpdateInput {')
      expect(output).not.toMatch(/UserUpdateInput \{[^}]*\bid:/)
      expect(output).not.toMatch(/UserUpdateInput \{[^}]*\bupdatedAt:/)
      expect(output).toMatch(/UserUpdateInput \{[^}]*email\?: string/)
    })

    it('generates WhereInput with all scalar fields optional', async () => {
      const output = await generate(dmmf)
      expect(output).toContain('export interface UserWhereInput {')
      expect(output).toMatch(/UserWhereInput \{[^}]*id\?: number/)
      expect(output).toMatch(/UserWhereInput \{[^}]*email\?: string/)
    })

    it('generates WhereUniqueInput with only @id and @unique fields', async () => {
      const output = await generate(dmmf)
      expect(output).toContain('export interface UserWhereUniqueInput {')
      expect(output).toMatch(/UserWhereUniqueInput \{[^}]*id\?: number/)
      expect(output).toMatch(/UserWhereUniqueInput \{[^}]*email\?: string/)
      // non-unique field must not appear
      expect(output).not.toMatch(/UserWhereUniqueInput \{[^}]*\bscore:/)
    })

    it('generates UserClient interface with all CRUD methods', async () => {
      const output = await generate(dmmf)
      expect(output).toContain('export interface UserClient {')
      expect(output).toContain('findMany(where?: UserWhereInput): Promise<User[]>')
      expect(output).toContain('findUnique(where: UserWhereUniqueInput): Promise<User | null>')
      expect(output).toContain('create(data: UserCreateInput): Promise<User>')
      expect(output).toContain('update(where: UserWhereUniqueInput, data: UserUpdateInput): Promise<User>')
      expect(output).toContain('delete(where: UserWhereUniqueInput): Promise<User>')
    })

    it('generates a createUserClient factory referencing the correct REST path', async () => {
      const output = await generate(dmmf)
      expect(output).toContain("function createUserClient(config: RestApiClientConfig): UserClient")
      expect(output).toContain("const base = '/user'")
    })
  })

  describe('PascalCase model name → kebab-case URL path', () => {
    it.each([
      ['User', '/user'],
      ['BlogPost', '/blog-post'],
      ['UserProfile', '/user-profile'],
    ])('%s → %s', async (modelName, expectedPath) => {
      const dmmf = makeDmmf([{ name: modelName, fields: [{ name: 'id', type: 'Int', isId: true }] }])
      const output = await generate(dmmf)
      expect(output).toContain(`const base = '${expectedPath}'`)
    })
  })

  describe('enum generation', () => {
    const dmmf = makeDmmf(
      [
        {
          name: 'Post',
          fields: [
            { name: 'id', type: 'Int', isId: true, hasDefaultValue: true },
            { name: 'status', kind: 'enum' as const, type: 'PostStatus' },
          ],
        },
      ],
      [{ name: 'PostStatus', values: [{ name: 'DRAFT', dbName: null }, { name: 'PUBLISHED', dbName: null }] }],
    )

    it('generates const enum objects', async () => {
      const output = await generate(dmmf)
      expect(output).toContain("export const PostStatus = {")
      expect(output).toContain("DRAFT: 'DRAFT',")
      expect(output).toContain("PUBLISHED: 'PUBLISHED',")
      expect(output).toContain('} as const')
    })

    it('generates the companion union type', async () => {
      const output = await generate(dmmf)
      expect(output).toContain('export type PostStatus = (typeof PostStatus)[keyof typeof PostStatus]')
    })

    it('references the enum type in model interfaces', async () => {
      const output = await generate(dmmf)
      expect(output).toMatch(/status: PostStatus/)
    })
  })

  describe('PrismaRestApiClient', () => {
    it('generates the top-level client interface with camelCase model properties', async () => {
      const dmmf = makeDmmf([
        { name: 'User', fields: [{ name: 'id', type: 'Int', isId: true }] },
        { name: 'BlogPost', fields: [{ name: 'id', type: 'Int', isId: true }] },
      ])
      const output = await generate(dmmf)
      expect(output).toContain('export interface PrismaRestApiClient {')
      expect(output).toContain('user: UserClient')
      expect(output).toContain('blogPost: BlogPostClient')
    })

    it('generates createPrismaRestApiClient factory', async () => {
      const dmmf = makeDmmf([{ name: 'User', fields: [{ name: 'id', type: 'Int', isId: true }] }])
      const output = await generate(dmmf)
      expect(output).toContain('export function createPrismaRestApiClient(config: RestApiClientConfig): PrismaRestApiClient')
      expect(output).toContain('user: createUserClient(config)')
    })
  })

  it('handles a schema with no models', async () => {
    const output = await generate(makeDmmf([]))
    expect(output).toContain('export interface PrismaRestApiClient {')
    expect(output).toContain('export function createPrismaRestApiClient')
  })

  it('handles list fields', async () => {
    const dmmf = makeDmmf([
      {
        name: 'User',
        fields: [
          { name: 'id', type: 'Int', isId: true },
          { name: 'tags', type: 'String', isList: true },
        ],
      },
    ])
    const output = await generate(dmmf)
    expect(output).toContain('tags: string[]')
  })
})

